import{c as t,Q as n,j as r,m as a}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Anthropic: Harness Design for Long-Running Application Development","description":"","frontmatter":{"url":"https://www.anthropic.com/engineering/harness-design-long-running-apps","date":"2026-05-09T00:00:00.000Z","authors":"Anthropic Team","source":"Anthropic Official Engineering Blog","tags":["harness-design","agent-architecture","evaluator-agent","Model-Harness-Fit"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-09-anthropic-harness-design-long-running-apps.md","filePath":"research/ai-articles/scored/2026-05-09-anthropic-harness-design-long-running-apps.md","lastUpdated":1779894392000}'),s={name:"research/ai-articles/scored/2026-05-09-anthropic-harness-design-long-running-apps.md"};function o(i,e,l,d,c,h){return n(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="anthropic-harness-design-for-long-running-application-development" tabindex="-1">Anthropic: Harness Design for Long-Running Application Development <a class="header-anchor" href="#anthropic-harness-design-for-long-running-application-development" aria-label="Permalink to &quot;Anthropic: Harness Design for Long-Running Application Development&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://www.anthropic.com/engineering/harness-design-long-running-apps" target="_blank" rel="noreferrer">https://www.anthropic.com/engineering/harness-design-long-running-apps</a><br><strong>作者</strong>：Anthropic Team<br><strong>歸檔日期</strong>：2026-05-09</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Anthropic 官方展示三代理 harness（planner、generator、evaluator）設計，實現單一 Agent 難以達成的長時間自主開發任務。核心洞見：harness 各元件編碼「模型無法自行完成的假設」；當模型能力進化時，該假設需重新審視。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><ol><li><p><strong>Agent + Harness 的共進化</strong>（Co-evolution）</p><ul><li>每個 harness 元件編碼一項假設：「模型在這個能力上不足」</li><li>當模型能力提升時，舊假設變成死重，應移除</li><li>新模型解鎖新能力時，需要新的 harness scaffolding 才能達到天花板</li></ul></li><li><p><strong>Playwright MCP 工具端設計</strong></p><ul><li>Evaluator agent 直接與執行中的應用互動（screenshotting、navigation）</li><li>工具表面形狀決定了模型能直觀執行的任務類型</li><li>與推文 @nicbstme 「Tool Surface is Model&#39;s Vocabulary」呼應</li></ul></li><li><p><strong>多代理分工的性能躍升</strong></p><ul><li>Solo Agent 結果：20 分鐘、$9、核心功能破損</li><li>三代理 Harness 結果：6 小時、$200、完整可玩遊戲 + 16 項功能規格</li><li>品質大幅提升的代價是 context 和 token 消耗增加</li></ul></li></ol><hr><h2 id="直接意涵" tabindex="-1">直接意涵 <a class="header-anchor" href="#直接意涵" aria-label="Permalink to &quot;直接意涵&quot;">​</a></h2><h3 id="cc-workspace-可行動性" tabindex="-1">cc-workspace 可行動性 <a class="header-anchor" href="#cc-workspace-可行動性" aria-label="Permalink to &quot;cc-workspace 可行動性&quot;">​</a></h3><ol><li><p><strong>CLAUDE.md 的 <code>&lt;system-reminder&gt;</code> 注入是 harness 過擬合的證據</strong></p><ul><li>該機制明確編碼「Claude 會讀 system-reminder tag 並改變行為」</li><li>其他模型如未 post-train 認識此 tag，會無視它</li><li>跨模型移植 CLAUDE.md 時需警覺此耦合</li></ul></li><li><p><strong>「harness 元件會隨模型成熟過時」適用於 subagent-strategy.md</strong></p><ul><li>當前規則中 Haiku 4.5 的「context reset machinery」可能變成 dead weight（推文參考 Opus 4.6 已移除此機制）</li><li>年度 audit 必須檢查：這項 harness 元件還在補哪個模型的缺口？</li><li>與 research/agent-harness/eval-2026-05-08.md 的「harness obsolescence tracking」相連</li></ul></li><li><p><strong>Multi-Agent 與 PGE 原則強化</strong></p><ul><li><code>.claude/rules/subagent-strategy.md</code> 的 Planner-Generator-Evaluator 拓撲直接呼應此文，不是巧合</li><li>Anthropic 本身採用三代理設計，驗證了 Opus 4.6/4.7 需要此分工才能達到長任務自主度</li></ul></li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>明確論述 harness 過時機制、工具設計形狀的約束，直接支持 cc-workspace「harness audit」決策</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>Co-evolution feedback loop 概念在推文 @nicbstme 已提出；此文貢獻是 Anthropic 官方確認 + 三代理具體實施</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>具體數據：solo(20min/$9) vs harness(6hr/$200)；實際產品案例（retro game）；但未進行 ablation 對比</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>架構清晰、Playwright MCP 工具細節充分；未深入 evaluation loop 內部設計</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>Agent harness 通用原則；但示例專注長時間開發任務，對短任務場景應用性未明確</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.6/10</strong></td><td>8×0.3 + 7×0.2 + 8×0.2 + 7×0.15 + 8×0.15 = 2.4+1.4+1.6+1.05+1.2 = 7.65</td></tr></tbody></table><p><strong>整合決策</strong>：Rule（補充進 <code>.claude/refs/harness-design.md</code> 的「harness obsolescence」段落）</p><hr><h2 id="引用關聯" tabindex="-1">引用關聯 <a class="header-anchor" href="#引用關聯" aria-label="Permalink to &quot;引用關聯&quot;">​</a></h2><ul><li>推文 @nicbstme 2026-05-04：「Tool Surface is Model&#39;s Vocabulary」</li><li><code>.claude/rules/subagent-strategy.md</code>：Planner-Generator-Evaluator 拓撲選擇</li><li><code>research/agent-harness/eval-2026-05-08.md</code>：Harness health audit framework</li><li><code>.claude/refs/model-selection-grid.md</code>：模型進化時 harness 需重新評估</li></ul>',19)])])}const u=t(s,[["render",o]]);export{p as __pageData,u as default};
